-        // Phase 1: reserve
-        let permit = tx.reserve(&cx).expect("reserve failed");
-
-        // Permit is held - capacity is reserved
-        assert_eq!(tx.capacity(), 10);
-
-        // Phase 2: commit
-        permit.send(42);
-
-        let value = rx.recv(&cx).expect("recv failed");
-        assert_eq!(value, 42);
