-            for &task in tasks {
-                if !self.completed_tasks.contains(&task) {
-                    leaked.push(task);
-                }
-            }
-
-            if !leaked.is_empty() {
-                return Err(TaskLeakViolation {
-                    region,
-                    leaked_tasks: leaked,
-                    region_close_time: close_time,
-                });
-            }
-        }
