-
-        for v in violations {
-            let InvariantViolation::Futurelock {
-                task,
-                region,
-                idle_steps,
-                held,
-            } = v
-            else {
-                continue;
-            };
-
-            let mut held_kinds = Vec::new();
-            for oid in &held {
-                for (_, obligation) in self.state.obligations.iter() {
