-use core::fmt;
-
-/// An index into an arena with a generation counter for ABA safety.
-#[derive(Clone, Copy, PartialEq, Eq, Hash)]
-pub struct ArenaIndex {
-    index: u32,
-    generation: u32,
-}
-
-impl ArenaIndex {
-    /// Creates a new arena index (primarily for testing).
