-    pub const fn new(index: u32, generation: u32) -> Self {
-        Self { index, generation }
-    }
-
-    /// Returns the raw index value.
-    #[must_use]
-    pub const fn index(self) -> u32 {
-        self.index
-    }
-
-    /// Returns the generation counter.
-    #[must_use]
-    pub const fn generation(self) -> u32 {
-        self.generation
-    }
-}
