-            match slot {
-                Slot::Vacant {
-                    next_free,
-                    generation,
-                } => {
-                    let gen = *generation;
-                    self.free_head = *next_free;
-                    *slot = Slot::Occupied {
-                        value,
-                        generation: gen,
-                    };
-                    ArenaIndex {
-                        index: free_index,
-                        generation: gen,
-                    }
-                }
-                Slot::Occupied { .. } => unreachable!("free list pointed to occupied slot"),
-            }
-        } else {
-            let index = u32::try_from(self.slots.len()).expect("arena overflow");
-            self.slots.push(Slot::Occupied {
-                value,
-                generation: 0,
-            });
