-                    ArenaIndex {
-                        index: i as u32,
-                        generation: *generation,
-                    },
-                    value,
-                )),
-                Slot::Vacant { .. } => None,
-            })
-    }
-
-    /// Iterates mutably over all occupied slots.
-    pub fn iter_mut(&mut self) -> impl Iterator<Item = (ArenaIndex, &mut T)> {
-        self.slots
-            .iter_mut()
-            .enumerate()
-            .filter_map(|(i, slot)| match slot {
-                Slot::Occupied { value, generation } => Some((
-                    ArenaIndex {
-                        index: i as u32,
-                        generation: *generation,
-                    },
-                    value,
-                )),
-                Slot::Vacant { .. } => None,
-            })
-    }
-}
-
